jobs:
  release:
    name: Release (${{ inputs.channel }}${{ inputs.channel != 'finalize' && format(' {0}', inputs.bump) || '' }})
    runs-on: ubuntu-latest
    outputs:
      publish_action: ${{ steps.bump.outputs.publish_action }}
      release_tag: ${{ steps.bump.outputs.release_tag }}
    steps:
      - uses: actions/checkout@v4
        with:
          fetch-depth: 0

      - name: Configure git
        run: |
          git config user.name "github-actions[bot]"
          git config user.email "github-actions[bot]@users.noreply.github.com"
          git checkout main

      - name: Resolve finalize ref
        if: inputs.channel == 'finalize'
        id: finalize_ref
        run: |
          if [ -n "${{ inputs.prerelease_tag }}" ]; then
            TAG="${{ inputs.prerelease_tag }}"
          else
            TAG=$(git tag --list 'v*-next.*' --sort=-version:refname | head -n 1)
          fi

          case "$TAG" in
            v*) ;;
            *) TAG="v$TAG" ;;
          esac

          if [ -z "$TAG" ]; then
            echo "No prerelease tag found to finalize" >&2
            exit 1
          fi

          echo "tag=$TAG" >> "$GITHUB_OUTPUT"
          git checkout --detach "$TAG"

      - name: Setup Bun
        uses: oven-sh/setup-bun@v2
        with:
          bun-version-file: package.json

      - name: Install dependencies
        run: bun install --frozen-lockfile

