            PUBLISH_ACTION="publish-next"
          else
            PUBLISH_ACTION="publish-latest"
          fi

          echo "version=$VERSION" >> "$GITHUB_OUTPUT"
          echo "release_tag=$RELEASE_TAG" >> "$GITHUB_OUTPUT"
          echo "publish_action=$PUBLISH_ACTION" >> "$GITHUB_OUTPUT"

