    name: Publish npm packages
    needs: release
    uses: ./.github/workflows/publish.yml
    permissions:
      contents: read
      id-token: write
    with:
      action: ${{ needs.release.outputs.publish_action }}
      ref: ${{ needs.release.outputs.release_tag }}
    secrets:
